// client/hooks/useResizeObserver.ts
import { useCallback, useEffect, useRef, useState } from 'react';
export function useResizeObserver<T extends Element = HTMLDivElement>(opts: { debounceMs?: number } = {}) {
  const [size, setSize] = useState<{ width: number; height: number } | null>(null);
  const elementRef = useRef<T | null>(null);
  const timerRef = useRef<number | null>(null);
  const setRef = useCallback((node: T | null) => {
    elementRef.current = node;
  }, []);
  useEffect(() => {
    const el = elementRef.current;
    if (!el || typeof ResizeObserver === 'undefined') return;
    const ro = new ResizeObserver((entries) => {
      const entry = entries[0];
      if (!entry) return;
      const apply = () => setSize({ width: entry.contentRect.width, height: entry.contentRect.height });
      if (opts.debounceMs) {
        if (timerRef.current) clearTimeout(timerRef.current);
        timerRef.current = window.setTimeout(apply, opts.debounceMs);
      } else apply();
    });
    ro.observe(el);
    return () => { ro.disconnect(); if (timerRef.current) clearTimeout(timerRef.current); };
  }, [opts.debounceMs]);
  return [setRef, size] as const;
}

// usage
function ResponsiveChart() {
  const [ref, size] = useResizeObserver<HTMLDivElement>({ debounceMs: 100 });
  return <div ref={ref}>{size && <Chart width={size.width} height={size.height} />}</div>;
}

