// client/hooks/useFormField.ts
import { useCallback, useState, useMemo } from 'react';
import { z, ZodSchema } from 'zod';
export function useFormField<T>(schema: ZodSchema<T>, initial: T) {
  const [value, setValue] = useState<T>(initial);
  const [touched, setTouched] = useState(false);
  const [dirty, setDirty] = useState(false);
  const error = useMemo(() => {
    const r = schema.safeParse(value);
    return r.success ? null : r.error.issues[0]?.message ?? 'Invalid';
  }, [value, schema]);
  const onChange = useCallback((next: T) => { setValue(next); if (!dirty) setDirty(true); }, [dirty]);
  const onBlur = useCallback(() => setTouched(true), []);
  const reset = useCallback(() => { setValue(initial); setTouched(false); setDirty(false); }, [initial]);
  return {
    value, setValue: onChange, onBlur, reset,
    error, dirty, touched,
    showError: touched && !!error,
    inputProps: { value: value as any, onChange: (e: React.ChangeEvent<HTMLInputElement>) => onChange(e.target.value as any), onBlur, 'aria-invalid': touched && !!error }
  };
}

// usage
import { z } from 'zod';
function EmailInput() {
  const email = useFormField(z.string().email('Enter a valid email'), '');
  return (
    <div>
      <input {...email.inputProps} type="email" />
      {email.showError && <p className="text-red-600 text-sm">{email.error}</p>}
    </div>
  );
}

