}
export class InsufficientFundsError extends AppError { readonly code = 'INSUFFICIENT_FUNDS' as const; readonly status = 402; }
export class FraudSuspectedError extends AppError { readonly code = 'FRAUD_SUSPECTED' as const; readonly status = 402; }

// server/services/paymentService.ts
import Stripe from 'stripe';
import { PaymentDeclinedError, ThreeDSRequiredError, InsufficientFundsError, FraudSuspectedError } from '../errors/payment';
export const paymentService = {
  async charge(input: { amount: number; paymentMethodId: string }) {
    try {
      const intent = await stripe.paymentIntents.create({ amount: input.amount, currency: 'usd', payment_method: input.paymentMethodId, confirm: true, automatic_payment_methods: { enabled: true } });
      if (intent.status === 'requires_action') throw new ThreeDSRequiredError(intent.client_secret!);
      if (intent.status !== 'succeeded') throw new PaymentDeclinedError(`Payment status: ${intent.status}`);
      return { id: intent.id };
    } catch (e: any) {
      if (e instanceof AppError) throw e;
      if (e.type === 'StripeCardError') {
        switch (e.code) {
          case 'insufficient_funds': throw new InsufficientFundsError('Insufficient funds');
          case 'fraudulent': throw new FraudSuspectedError('Card flagged');
          default: throw new PaymentDeclinedError(e.message);
        }
      }
      throw e;
    }
  }
};

