      await fetcher('/api/payments/charge', { method: 'POST', headers: { 'content-type': 'application/json' }, body: JSON.stringify({ paymentMethodId, amount }) }, () => undefined);
      setStatus('idle');
    } catch (e) {
      if (e instanceof FetchError && e.body) {
        switch (e.body.code) {
          case 'THREE_DS_REQUIRED':
            if (!stripe) return;
            const result = await stripe.handleCardAction((e.body.meta as any).clientSecret);
            if (result.error) setErrorMsg('Authentication failed');
            else { await pay(); return; }
            break;
          case 'INSUFFICIENT_FUNDS': setErrorMsg('Insufficient funds. Try another card.'); break;
          case 'FRAUD_SUSPECTED': setErrorMsg('Card flagged. Contact your bank.'); break;
          case 'PAYMENT_DECLINED': setErrorMsg('Card declined. Try another payment method.'); break;
          default: setErrorMsg('Payment failed. Try again.');
        }
      }
      setStatus('error');
    }
  };
  return <div><button disabled={status === 'processing'} onClick={pay}>Pay ${(amount/100).toFixed(2)}</button>{errorMsg && <p role="alert" className="text-red-600">{errorMsg}</p>}</div>;
}

