let online = navigator.onLine;
const listeners = new Set<(online: boolean) => void>();
export function getOnline() { return online; }
export function onConnectivityChange(cb: (online: boolean) => void) { listeners.add(cb); return () => listeners.delete(cb); }
function setOnline(next: boolean) { if (next === online) return; online = next; listeners.forEach(cb => cb(next)); }
export async function probeInternet(): Promise<boolean> {
  try {
    const ac = new AbortController();
    setTimeout(() => ac.abort(), 3000);
    const r = await fetch('/health', { signal: ac.signal, cache: 'no-store' });
    return r.ok;
  } catch { return false; }
}
window.addEventListener('online', async () => { if (await probeInternet()) setOnline(true); });
window.addEventListener('offline', () => setOnline(false));
let probeTimer: number | null = null;
export function scheduleProbe() {
  if (probeTimer) return;
  probeTimer = window.setTimeout(async () => {
    probeTimer = null;
    const isOnline = await probeInternet();
    setOnline(isOnline);
    if (!isOnline) scheduleProbe();
  }, 5000);
}

