import { Router } from 'express';
import { routes } from '@shared/routes';
import { validateBody } from '../middleware/validateBody';
export function registerRpcRoutes(handlers: { [K in keyof typeof routes]: (input: any) => Promise<any> }) {
  const r = Router();
  for (const [key, def] of Object.entries(routes)) {
    const handler = handlers[key as keyof typeof routes];
    const path = (def as any).path({}) === undefined ? '/' : (def as any).path({ id: ':id' });
    r[def.method.toLowerCase() as 'get'|'post'](path, validateBody(def.input), async (req, res, next) => {
