// server/services/cacheService.ts
import { redis } from '../redis';
import { tenantContext } from '../context/tenantContext';
import { logger } from '../logger';
const inflight = new Map<string, Promise<any>>();
export const cacheService = {
  async getOrSet<T>(key: string, ttlSeconds: number, loader: () => Promise<T>): Promise<T> {
    const tenantId = tenantContext.requireTenant();
    const fullKey = `t:${tenantId}:${key}`;
    const cached = await redis.get(fullKey);
    if (cached) { logger.debug({ key: fullKey }, 'cache_hit'); return JSON.parse(cached); }
    const existing = inflight.get(fullKey);
    if (existing) return existing as Promise<T>;
    const p = (async () => {
      try {
        const value = await loader();
        await redis.setex(fullKey, ttlSeconds, JSON.stringify(value));
        return value;
      } finally { inflight.delete(fullKey); }
    })();
    inflight.set(fullKey, p);
    return p;
  },
  async invalidate(key: string) {
    const tenantId = tenantContext.requireTenant();
    const fullKey = `t:${tenantId}:${key}`;
    await redis.del(fullKey);
    await redis.publish('cache:invalidate', fullKey);
  }
};

// pub/sub subscriber for in-memory secondary caches
import { redis } from '../redis';
import { localCache } from './localCache';
const sub = redis.duplicate();
sub.subscribe('cache:invalidate');
sub.on('message', (_chan, key) => localCache.delete(key));

