// client/lib/strictFetcher.ts
import { z } from 'zod';
export async function strictFetch<T>(url: string, init: RequestInit, schema: z.ZodSchema<T>): Promise<T> {
  const res = await fetch(url, init);
  const ct = res.headers.get('content-type') ?? '';
  if (!ct.includes('application/json')) {
    const text = await res.text();
    throw new Error(`Expected JSON, got ${ct}. Sample: ${text.slice(0, 200)}`);
  }
  const text = await res.text();
  let parsed;
  try { parsed = JSON.parse(text); }
  catch (e) { throw new Error(`JSON parse failed for ${url}: ${text.slice(0, 200)}`); }
  return schema.parse(parsed);
}

