// server/services/permissionsService.ts
import { redis } from '../redis';
import { ROLE_GRANTS, Role } from '@shared/schemas/permissions';
import { userDal } from '../dal/userDal';
const cache = new Map<string, { role: Role; expires: number }>();
const TTL_MS = 60_000;
export const permissionsService = {
  async getRole(userId: string): Promise<Role> {
    const cached = cache.get(userId);
    if (cached && cached.expires > Date.now()) return cached.role;
    const user = await userDal.byId(userId);
    cache.set(userId, { role: user.role, expires: Date.now() + TTL_MS });
    return user.role;
  },
  invalidate(userId: string) {
    cache.delete(userId);
    redis.publish('perm:invalidate', userId);
  },
  async changeRole(userId: string, newRole: Role) {
    await userDal.updateRole(userId, newRole);
    this.invalidate(userId);
  }
};
const sub = redis.duplicate();
sub.subscribe('perm:invalidate');
sub.on('message', (_chan, userId) => cache.delete(userId));

