// shared/lib/result.ts (extended)
export type Result<T, E = Error> = Ok<T> | Err<E>;
interface Ok<T> { ok: true; value: T; andThen<U, E>(fn: (v: T) => Result<U, E>): Result<U, E>; map<U>(fn: (v: T) => U): Ok<U>; mapErr<F>(fn: (e: never) => F): Ok<T>; }
interface Err<E> { ok: false; error: E; andThen<U, F>(fn: (v: never) => Result<U, F>): Err<E>; map<U>(fn: (v: never) => U): Err<E>; mapErr<F>(fn: (e: E) => F): Err<F>; }
export function ok<T>(value: T): Ok<T> { return { ok: true, value, andThen: (fn) => fn(value), map: (fn) => ok(fn(value)), mapErr: () => ok(value) }; }
export function err<E>(error: E): Err<E> { return { ok: false, error, andThen: () => err(error), map: () => err(error), mapErr: (fn) => err(fn(error)) }; }

