// server/services/quotaService.ts
import { QuotaError } from '../errors';
import { redis } from '../redis';
import { tenantContext } from '../context/tenantContext';
const PLAN_LIMITS: Record<string, Record<string, { soft: number; hard: number }>> = {
  free: { projects: { soft: 10, hard: 15 }, members: { soft: 3, hard: 5 } },
  pro: { projects: { soft: 100, hard: 200 } }
};
export const quotaService = {
  async get(kind: string) {
    const tenantId = tenantContext.requireTenant();
    const plan = (await tenantDal.byId(tenantId)).plan;
    const used = parseInt((await redis.get(`quota:${tenantId}:${kind}`)) ?? '0', 10);
    const { soft, hard } = PLAN_LIMITS[plan]?.[kind] ?? { soft: Infinity, hard: Infinity };
    return { kind, used, softLimit: soft, hardLimit: hard };
  },
  async increment(kind: string) {
    const tenantId = tenantContext.requireTenant();
    const info = await this.get(kind);
    if (info.used >= info.hardLimit) throw new QuotaError(`${kind} limit reached`, { meta: { kind, used: info.used, hardLimit: info.hardLimit, upgradeUrl: '/billing/upgrade' } });
    await redis.incr(`quota:${tenantId}:${kind}`);
  },
  async decrement(kind: string) {
    const tenantId = tenantContext.requireTenant();
    await redis.decr(`quota:${tenantId}:${kind}`);
  }
};

