// server/services/inviteAcceptService.ts
import mongoose from 'mongoose';
export const inviteAcceptService = {
  async accept(inviteId: string, userId: string) {
    const session = await mongoose.startSession();
    session.startTransaction({ readConcern: { level: 'snapshot' }, writeConcern: { w: 'majority' } });
    try {
      const invite = await InviteModel.findById(inviteId).session(session);
      if (!invite || invite.status !== 'pending') {
        await session.abortTransaction();
        if (invite?.status === 'accepted' && invite.acceptedBy === userId) return { alreadyAccepted: true };
        throw new ConflictError('Invite no longer valid');
      }
      invite.status = 'accepted';
      invite.acceptedBy = userId;
      await invite.save({ session });
      await MembershipModel.create([{ userId, tenantId: invite.tenantId, role: invite.role }], { session });
      await session.commitTransaction();
      return { ok: true };
    } catch (e) {
      await session.abortTransaction();
      throw e;
    } finally { session.endSession(); }
  }
};

